import React from 'react';
import { Phone } from 'lucide-react';

function Header() {
  return (
    <header className="sticky top-0 z-50 bg-primary-dark/95 backdrop-blur-sm text-white border-b border-white/10 py-3 shadow-soft transition-all">
      <div className="container mx-auto px-6 flex justify-between items-center">
        <div className="flex items-center space-x-2">
          {/* Logo hiện đại, gọn gàng */}
          <img src="/logo.png" alt="Shipus.net Logo" className="h-10 transition-transform hover:scale-105" />
        </div>

        <nav className="hidden md:flex space-x-8 items-center font-sans">
          <a href="#" className="text-sm font-medium hover:text-primary-accent transition-colors">TRANG CHỦ</a>
          <a href="#pricing" className="text-sm font-medium hover:text-primary-accent transition-colors">BẢNG GIÁ</a>
          <a href="#guide" className="text-sm font-medium hover:text-primary-accent transition-colors">HƯỚNG DẪN</a>
          <a href="#tracking" className="text-sm font-medium hover:text-primary-accent transition-colors">TRA CỨU</a>
        </nav>

        <button className="bg-primary-accent hover:bg-orange-700 text-white font-semibold py-2 px-6 rounded-md flex items-center space-x-2 transition-all shadow-md active:scale-95 text-sm uppercase tracking-wider">
          <Phone size={16} strokeWidth={1.5} />
          <span>Liên hệ</span>
        </button>
      </div>
    </header>
  );
}

export default Header;
